<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Personal Expense Tracker</title>
<style>
  * { box-sizing: border-box; }
  body {
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    margin: 0;
    padding: 20px;
    background: #f5f6f8;
    color: #222;
    line-height: 1.5;
  }
  h1 { margin: 0 0 16px; font-size: 1.6rem; }
  h2 { margin: 24px 0 8px; font-size: 1.15rem; }
  .layout {
    max-width: 920px;
    margin: 0 auto;
    display: grid;
    grid-template-columns: 320px 1fr;
    gap: 24px;
  }
  @media (max-width: 720px) { .layout { grid-template-columns: 1fr; } }
  .panel {
    background: #fff;
    border: 1px solid #e3e5ea;
    border-radius: 8px;
    padding: 16px;
  }
  label { display: block; font-size: 0.85rem; margin: 10px 0 4px; font-weight: 600; }
  input, select, textarea {
    width: 100%;
    padding: 8px 10px;
    font-size: 0.95rem;
    border: 1px solid #cfd3da;
    border-radius: 6px;
    background: #fff;
    font-family: inherit;
  }
  textarea { resize: vertical; min-height: 48px; }
  button {
    cursor: pointer;
    border: none;
    border-radius: 6px;
    padding: 9px 14px;
    font-size: 0.95rem;
    font-family: inherit;
    background: #2b6cb0;
    color: #fff;
  }
  button:hover { background: #245a99; }
  button.secondary { background: #6b7280; }
  button.secondary:hover { background: #5a626d; }
  #form-error {
    color: #b00020;
    font-size: 0.85rem;
    min-height: 1.2em;
    margin-top: 8px;
  }
  .filters { display: grid; grid-template-columns: 1fr 1fr; gap: 8px; }
  .filters .full { grid-column: 1 / -1; }
  .summary-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(140px, 1fr));
    gap: 8px;
    margin-top: 8px;
  }
  .cat-total {
    background: #f0f3f7;
    border: 1px solid #e3e5ea;
    border-radius: 6px;
    padding: 8px 10px;
    font-size: 0.85rem;
  }
  .cat-total .cat-name { text-transform: capitalize; font-weight: 600; display: block; }
  .cat-total .cat-amount { color: #2b6cb0; font-weight: 700; }
  #total {
    font-size: 1.4rem;
    font-weight: 700;
    color: #1f2937;
  }
  .total-label { font-size: 0.85rem; color: #6b7280; }
  ul#expense-list { list-style: none; margin: 0; padding: 0; }
  .expense {
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 10px 12px;
    border: 1px solid #e3e5ea;
    border-radius: 6px;
    margin-bottom: 8px;
    background: #fff;
  }
  .expense .amt { font-weight: 700; color: #1f2937; min-width: 80px; }
  .expense .cat {
    background: #eef2f7;
    color: #2b6cb0;
    border-radius: 12px;
    padding: 2px 10px;
    font-size: 0.8rem;
    text-transform: capitalize;
  }
  .expense .dt { color: #6b7280; font-size: 0.85rem; }
  .expense .nt { color: #4b5563; font-size: 0.85rem; flex: 1; }
  .expense .exp-del { margin-left: auto; background: #b00020; padding: 6px 10px; font-size: 0.8rem; }
  .expense .exp-del:hover { background: #8a0019; }
  .empty { color: #9ca3af; font-style: italic; padding: 12px; text-align: center; }
</style>
</head>
<body>
<div class="layout">
  <section class="panel" id="entry-panel">
    <h1>Expense Tracker</h1>
    <form id="expense-form" autocomplete="off">
      <label for="amount">Amount</label>
      <input type="number" id="amount" step="0.01" min="0.01" placeholder="0.00" />

      <label for="category">Category</label>
      <select id="category">
        <option value="groceries">Groceries</option>
        <option value="transport">Transport</option>
        <option value="bills">Bills</option>
        <option value="fun">Fun</option>
      </select>

      <label for="date">Date</label>
      <input type="date" id="date" />

      <label for="note">Note (optional)</label>
      <textarea id="note"></textarea>

      <div style="margin-top:12px;">
        <button type="submit" id="add-expense">Add Expense</button>
      </div>
      <div id="form-error" role="alert" aria-live="polite"></div>
    </form>

    <h2>Filters</h2>
    <div class="filters">
      <label for="filter-category" class="full" style="margin-top:0;">Category</label>
      <select id="filter-category" class="full">
        <option value="all">All</option>
        <option value="groceries">Groceries</option>
        <option value="transport">Transport</option>
        <option value="bills">Bills</option>
        <option value="fun">Fun</option>
      </select>
      <label for="filter-from">From</label>
      <label for="filter-to">To</label>
      <input type="date" id="filter-from" />
      <input type="date" id="filter-to" />
      <div class="full">
        <button type="button" class="secondary" id="clear-filters">Clear Filters</button>
      </div>
    </div>
  </section>

  <section class="panel" id="list-panel">
    <div style="display:flex; justify-content:space-between; align-items:baseline; flex-wrap:wrap; gap:8px;">
      <h2 style="margin:0;">Expenses</h2>
      <div>
        <span class="total-label">Total (visible): </span>
        <span id="total">0.00</span>
      </div>
    </div>

    <div class="summary-grid" id="category-summary"></div>

    <ul id="expense-list" style="margin-top:16px;"></ul>
    <div class="empty" id="empty-state">No expenses to display.</div>
  </section>
</div>

<script>
(function () {
  "use strict";

  var STORAGE_KEY = "expense_tracker_v1";
  var CATEGORIES = ["groceries", "transport", "bills", "fun"];

  var state = {
    expenses: []
  };

  // ---------- Storage ----------
  function load() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        var parsed = JSON.parse(raw);
        if (Array.isArray(parsed)) state.expenses = parsed;
      }
    } catch (e) {
      state.expenses = [];
    }
  }
  function save() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(state.expenses));
    } catch (e) {}
  }

  // ---------- Helpers ----------
  function fmt(n) {
    return n.toFixed(2);
  }
  function escapeHtml(s) {
    return String(s)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&#39;");
  }
  function todayStr() {
    var d = new Date();
    var m = String(d.getMonth() + 1).padStart(2, "0");
    var day = String(d.getDate()).padStart(2, "0");
    return d.getFullYear() + "-" + m + "-" + day;
  }

  // ---------- Form ----------
  var formEl = document.getElementById("expense-form");
  var amountEl = document.getElementById("amount");
  var categoryEl = document.getElementById("category");
  var dateEl = document.getElementById("date");
  var noteEl = document.getElementById("note");
  var formErrorEl = document.getElementById("form-error");

  dateEl.value = todayStr();

  formEl.addEventListener("submit", function (e) {
    e.preventDefault();
    var rawAmount = amountEl.value;
    var amountNum = parseFloat(rawAmount);
    var dateVal = dateEl.value;

    // Validation
    if (rawAmount === "" || rawAmount === null || isNaN(amountNum) || !isFinite(amountNum) || amountNum <= 0) {
      formErrorEl.textContent = "Please enter a valid positive amount.";
      return;
    }
    if (!dateVal) {
      formErrorEl.textContent = "Please select a date.";
      return;
    }

    // Valid
    formErrorEl.textContent = "";

    var expense = {
      id: Date.now().toString(36) + Math.random().toString(36).slice(2, 8),
      amount: Math.round(amountNum * 100) / 100,
      category: categoryEl.value,
      date: dateVal,
      note: noteEl.value.trim()
    };
    state.expenses.push(expense);
    save();

    // Reset amount field (and note per good UX, but contract only requires amount)
    amountEl.value = "";
    noteEl.value = "";
    amountEl.focus();

    render();
  });

  // ---------- Filters ----------
  var filterCategoryEl = document.getElementById("filter-category");
  var filterFromEl = document.getElementById("filter-from");
  var filterToEl = document.getElementById("filter-to");
  var clearFiltersBtn = document.getElementById("clear-filters");

  filterCategoryEl.addEventListener("change", render);
  filterFromEl.addEventListener("change", render);
  filterToEl.addEventListener("change", render);
  clearFiltersBtn.addEventListener("click", function () {
    filterCategoryEl.value = "all";
    filterFromEl.value = "";
    filterToEl.value = "";
    render();
  });

  // ---------- List rendering ----------
  var listEl = document.getElementById("expense-list");
  var totalEl = document.getElementById("total");
  var summaryEl = document.getElementById("category-summary");
  var emptyStateEl = document.getElementById("empty-state");

  function isVisible(exp) {
    var cat = filterCategoryEl.value;
    if (cat !== "all" && exp.category !== cat) return false;

    var from = filterFromEl.value;
    var to = filterToEl.value;
    if (from && exp.date < from) return false;
    if (to && exp.date > to) return false;
    return true;
  }

  function render() {
    // Sort newest first (by date desc, then by insertion order desc using id)
    var sorted = state.expenses.slice().sort(function (a, b) {
      if (a.date !== b.date) return a.date < b.date ? 1 : -1;
      return a.id < b.id ? 1 : -1;
    });

    listEl.innerHTML = "";
    var visibleTotal = 0;
    var catTotals = {};
    CATEGORIES.forEach(function (c) { catTotals[c] = 0; });

    var visibleCount = 0;
    sorted.forEach(function (exp) {
      var visible = isVisible(exp);
      if (visible) {
        visibleCount++;
        visibleTotal += exp.amount;
        catTotals[exp.category] = (catTotals[exp.category] || 0) + exp.amount;
      }

      var li = document.createElement("li");
      li.className = "expense";
      if (!visible) li.style.display = "none";

      var amt = document.createElement("span");
      amt.className = "amt";
      amt.textContent = "$" + fmt(exp.amount);

      var cat = document.createElement("span");
      cat.className = "cat";
      cat.textContent = exp.category;

      var dt = document.createElement("span");
      dt.className = "dt";
      dt.textContent = exp.date;

      var note = document.createElement("span");
      note.className = "nt";
      note.textContent = exp.note ? exp.note : "";

      var del = document.createElement("button");
      del.type = "button";
      del.className = "exp-del";
      del.textContent = "Delete";
      (function (id) {
        del.addEventListener("click", function () {
          state.expenses = state.expenses.filter(function (e) { return e.id !== id; });
          save();
          render();
        });
      })(exp.id);

      li.appendChild(amt);
      li.appendChild(cat);
      li.appendChild(dt);
      li.appendChild(note);
      li.appendChild(del);
      listEl.appendChild(li);
    });

    totalEl.textContent = fmt(visibleTotal);

    // Category summary
    summaryEl.innerHTML = "";
    CATEGORIES.forEach(function (c) {
      var div = document.createElement("div");
      div.className = "cat-total";
      div.setAttribute("data-cat", c);
      var name = document.createElement("span");
      name.className = "cat-name";
      name.textContent = c;
      var val = document.createElement("span");
      val.className = "cat-amount";
      val.textContent = "$" + fmt(catTotals[c] || 0);
      div.appendChild(name);
      div.appendChild(document.createTextNode(" "));
      div.appendChild(val);
      summaryEl.appendChild(div);
    });

    if (visibleCount === 0) {
      emptyStateEl.style.display = "block";
    } else {
      emptyStateEl.style.display = "none";
    }
  }

  // ---------- Init ----------
  load();
  render();
})();
</script>
</body>
</html>
